mapper.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY member_regist DESC) AS rn, FROM members
NVL(MEMBER_STATUS, 'ACTIVE') = 'ACTIVE'
AND (LOWER(MEMBER_NAME) LIKE '%' || LOWER(#{searchWord}) || '%' OR LOWER(MEMBER_ID) LIKE '%' || LOWER(#{searchWord}) || '%')
) WHERE rn BETWEEN #{startRow} AND #{endRow}

